import{_ as a,o as r,c as i,ag as n}from"./chunks/framework.DXGyWiRo.js";const m=JSON.parse('{"title":"Sharing Report Cards with Families","description":"","frontmatter":{},"headers":[],"relativePath":"report-cards/sharing.md","filePath":"report-cards/sharing.md"}'),t={name:"report-cards/sharing.md"};function s(o,e,h,l,d,c){return r(),i("div",null,[...e[0]||(e[0]=[n('<h1 id="sharing-report-cards-with-families" tabindex="-1">Sharing Report Cards with Families <a class="header-anchor" href="#sharing-report-cards-with-families" aria-label="Permalink to &quot;Sharing Report Cards with Families&quot;">​</a></h1><h2 id="generating-a-share-link" tabindex="-1">Generating a Share Link <a class="header-anchor" href="#generating-a-share-link" aria-label="Permalink to &quot;Generating a Share Link&quot;">​</a></h2><ol><li>Generate the report card (see <a href="/report-cards/generating.html">Generating Report Cards</a>)</li><li>In the preview tap <strong>Share</strong></li><li>A shareable link is generated automatically</li><li>Send via text, email, or any messaging app using the native share sheet</li></ol><h2 id="what-the-family-sees" tabindex="-1">What the Family Sees <a class="header-anchor" href="#what-the-family-sees" aria-label="Permalink to &quot;What the Family Sees&quot;">​</a></h2><p>The share link opens a read-only version of the report card in any browser — no Diamond Analytics account required. The family sees:</p><ul><li>The same report card layout you see in preview</li><li>All charts, stats, and coach comments</li><li>Team branding (team name and sport)</li></ul><p>They cannot edit anything, see other players, or access any other part of Diamond Analytics.</p><h2 id="link-expiration" tabindex="-1">Link Expiration <a class="header-anchor" href="#link-expiration" aria-label="Permalink to &quot;Link Expiration&quot;">​</a></h2><p>Share links expire after 30 days. After expiration the link shows a &quot;Report card no longer available&quot; message. Generate a new report card and share a fresh link if families need access after expiration.</p><h2 id="sharing-recommendations" tabindex="-1">Sharing Recommendations <a class="header-anchor" href="#sharing-recommendations" aria-label="Permalink to &quot;Sharing Recommendations&quot;">​</a></h2><p><strong>End of season</strong> — generate report cards for the full season and share with all families as a season summary.</p><p><strong>Mid-season check-in</strong> — share after a significant stretch of games (10+ games) when analytics are meaningful.</p><p><strong>After a mechanics session</strong> — share immediately after an Individual Practice session where you conducted assessments. The data is fresh and specific.</p><p><strong>Tournament weekend</strong> — share after a tournament where a player had a significant performance (good or bad) to provide context.</p><h2 id="privacy" tabindex="-1">Privacy <a class="header-anchor" href="#privacy" aria-label="Permalink to &quot;Privacy&quot;">​</a></h2><p>Report card links are not indexed by search engines and are not discoverable without the link. However treat them as semi-public — do not share links containing sensitive personal information beyond what is in the report card (player name, jersey number, stats).</p>',16)])])}const g=a(t,[["render",s]]);export{m as __pageData,g as default};
